package com.vidaysalud.veterinaria.inventarioservicio.controller;import com.vidaysalud.veterinaria.inventarioservicio.dto.*;import com.vidaysalud.veterinaria.inventarioservicio.service.InventarioService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/inventario") @RequiredArgsConstructor public class InventarioController{private final InventarioService s;@GetMapping public ResponseEntity<ApiResponse<List<MovimientoResponseDTO>>>l(){return ok("Movimientos obtenidos",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<MovimientoResponseDTO>>b(@PathVariable Integer id){return ok("Movimiento encontrado",s.buscar(id));}@GetMapping("/medicamento/{id}")public ResponseEntity<ApiResponse<List<MovimientoResponseDTO>>>m(@PathVariable Integer id){return ok("Movimientos del medicamento",s.porMedicamento(id));}@PostMapping("/movimientos")public ResponseEntity<ApiResponse<MovimientoResponseDTO>>c(@Valid @RequestBody MovimientoRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Movimiento registrado",s.registrar(d)));}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}